firmware_template.source:
#include "exponential_smooth.h"
static float _alpha=0.1,_val=0;static bool _first=true;
void ema_setup(float a){_alpha=a;_first=true;}
float ema_add(float v){if(_first){_val=v;_first=false;}else _val=_alpha*v+(1-_alpha)*_val;return _val;}
float ema_get(){return _val;}
void ema_reset(){_first=true;}
